"""Audit — cross-reference manifest against filesystem (read-only).

Public API:
    AuditResult  – dataclass with missing/stale/untracked lists
    run_audit()  – main entry point; returns AuditResult
"""

from __future__ import annotations

from dataclasses import dataclass, field
from pathlib import Path

from model_shelf.manifest import _sha256_dir_for_rebuild, load_manifest
from model_shelf.import_model import _sha256_file
from model_shelf.resolver import (
    SUPPORTED_FORMATS,
    Config,
    check_storage_available,
)


@dataclass
class AuditResult:
    """Result of a shelf audit."""

    missing: list[str] = field(default_factory=list)
    untracked: list[str] = field(default_factory=list)
    stale: list[str] = field(default_factory=list)

    def to_dict(self) -> dict:
        return {
            "missing": list(self.missing),
            "untracked": list(self.untracked),
            "stale": list(self.stale),
        }


def _build_manifest_tracked_set(
    shelf_root: Path, models: dict
) -> set[str]:
    """Build a set of absolute str paths for every file listed in the manifest."""
    tracked: set[str] = set()
    for entry in models.values():
        fmt = entry.get("format", "")
        if fmt not in SUPPORTED_FORMATS:
            continue
        repo_id = entry.get("repo_id", "")
        if "/" not in repo_id:
            continue
        publisher, _, repo_name = repo_id.partition("/")
        model_dir = shelf_root / fmt / publisher / repo_name
        for fname in entry.get("files", []):
            tracked.add(str(model_dir / fname))
    return tracked


def _should_skip_file(path: Path) -> bool:
    """Return True if the path should be excluded from the untracked scan."""
    if path.name.startswith("._"):
        return True
    if ".cache" in path.parts:
        return True
    return False


def run_audit(config: Config) -> AuditResult:
    """Cross-reference manifest entries against the filesystem.

    Returns AuditResult with:
      - missing:  repo_ids whose tracked files don't exist on disk
      - stale:    repo_ids whose SHA256 no longer matches the filesystem
      - untracked: filesystem paths (absolute str) not tracked in manifest
    """
    check_storage_available(config)
    shelf_root = config.shelf_root

    manifest = load_manifest(shelf_root)
    models = manifest.get("models", {})

    # Build the set of all manifest-tracked absolute paths
    tracked_paths = _build_manifest_tracked_set(shelf_root, models)

    # --- Missing + Stale checks ---
    missing: list[str] = []
    stale: list[str] = []

    for repo_id, entry in models.items():
        fmt = entry.get("format", "")
        if fmt not in SUPPORTED_FORMATS:
            continue
        if "/" not in repo_id:
            continue
        publisher, _, repo_name = repo_id.partition("/")
        model_dir = shelf_root / fmt / publisher / repo_name

        # Check that every tracked file exists
        all_exist = True
        for fname in entry.get("files", []):
            fp = model_dir / fname
            if not fp.is_file():
                all_exist = False
                break

        if not all_exist:
            missing.append(repo_id)
            continue  # Don't bother with stale check if files are missing

        # SHA256 check
        entry_sha = entry.get("sha256", "")
        if fmt == "gguf":
            # Single-file GGUF: use _sha256_file
            gguf_files = entry.get("files", [])
            if gguf_files:
                fp = model_dir / gguf_files[0]
                try:
                    current_sha = _sha256_file(fp)
                except OSError:
                    missing.append(repo_id)
                    continue
                if current_sha != entry_sha:
                    stale.append(repo_id)
        else:
            # MLX / safetensors: use _sha256_dir_for_rebuild (same exclusion logic
            # that rebuild_manifest uses, so audit won't flag expected differences)
            if model_dir.is_dir():
                try:
                    current_sha = _sha256_dir_for_rebuild(model_dir)
                except OSError:
                    missing.append(repo_id)
                    continue
                if current_sha != entry_sha:
                    stale.append(repo_id)
            else:
                missing.append(repo_id)

    # --- Untracked check ---
    untracked: list[str] = []
    for fmt in SUPPORTED_FORMATS:
        fmt_dir = shelf_root / fmt
        if not fmt_dir.is_dir():
            continue
        for f in fmt_dir.rglob("*"):
            if not f.is_file():
                continue
            if _should_skip_file(f):
                continue
            f_str = str(f)
            if f_str not in tracked_paths:
                untracked.append(f_str)

    return AuditResult(
        missing=sorted(missing),
        untracked=sorted(untracked),
        stale=sorted(stale),
    )

"""Remove a model from the shelf by repo_id.

Public API:
    RemoveResult  – dataclass with removed paths and hardlink warnings
    remove_model() – main entry point; dry-run by default
"""

from __future__ import annotations

import os

from dataclasses import dataclass, field
from pathlib import Path

from model_shelf.manifest import load_manifest, remove_manifest_entry
from model_shelf.resolver import (
    SUPPORTED_FORMATS,
    Config,
    check_storage_available,
)


@dataclass
class RemoveResult:
    """Result of a remove operation (dry-run or execute)."""

    removed: list[str] = field(default_factory=list)
    hardlinks_warn: list[str] = field(default_factory=list)

    def to_dict(self) -> dict:
        return {
            "removed": list(self.removed),
            "hardlinks_warn": list(self.hardlinks_warn),
        }


def _cleanup_empty_parents(shelf_root: Path, model_dir: Path) -> None:
    """Remove empty ancestor directories up to (but not including) shelf_root."""
    parent = model_dir
    while parent != shelf_root:
        try:
            if parent.is_dir() and not any(parent.iterdir()):
                parent.rmdir()
            else:
                break  # directory not empty, stop walking up
        except OSError:
            break
        parent = parent.parent


def remove_model(
    config: Config, repo_id: str, *, dry_run: bool = True
) -> RemoveResult:
    """Remove the model identified by *repo_id* from the shelf.

    Args:
        config:   Shelf configuration.
        repo_id:  Model identifier, e.g. "Qwen/Qwen3-14B-GGUF".
        dry_run:  If True (default), compute what would be removed without
                  actually deleting anything or updating the manifest.

    Returns:
        RemoveResult with the list of paths that were (or would be) removed
        and any hardlink warnings.

    Raises:
        ValueError if *repo_id* is not found in the manifest.
    """
    check_storage_available(config)
    shelf_root = config.shelf_root

    manifest = load_manifest(shelf_root)
    models = manifest.get("models", {})

    entry = models.get(repo_id)
    if entry is None:
        raise ValueError(f"model '{repo_id}' not found in manifest")

    fmt = entry.get("format", "")
    if fmt not in SUPPORTED_FORMATS:
        raise ValueError(f"unsupported format {fmt!r} in manifest entry for '{repo_id}'")

    # Reconstruct paths
    publisher, _, repo_name = repo_id.partition("/")
    model_dir = shelf_root / fmt / publisher / repo_name

    # Collect all file paths
    all_file_paths: list[Path] = []
    for fname in entry.get("files", []):
        fp = model_dir / fname
        if fp.is_file():
            all_file_paths.append(fp)

    # Hardlink check
    hardlinks_warn: list[str] = []
    for fp in all_file_paths:
        try:
            st = fp.stat()
        except OSError:
            continue
        if st.st_nlink > 1:
            hardlinks_warn.append(f"{fp} (st_nlink={st.st_nlink})")

    removed_paths = [str(p) for p in all_file_paths]

    if dry_run:
        return RemoveResult(
            removed=removed_paths,
            hardlinks_warn=hardlinks_warn,
        )

    # --- Execute ---
    for fp in all_file_paths:
        try:
            os.unlink(fp)
        except OSError:
            pass

    # Remove manifest entry
    remove_manifest_entry(shelf_root, repo_id)

    # Clean up empty parent directories
    _cleanup_empty_parents(shelf_root, model_dir)

    return RemoveResult(
        removed=removed_paths,
        hardlinks_warn=hardlinks_warn,
    )

"""Garbage collection — find and clean up incomplete downloads, orphaned
files, and empty directories on the curated shelf.

Dry-run by default.  Never touches .cache/ or dot-prefixed paths.

Public API:
    GCResult  – dataclass with lists and reclaimable byte count
    run_gc()  – main entry point (scan-only; execution happens in CLI)
"""

from __future__ import annotations

import os
import shutil

from dataclasses import dataclass, field
from pathlib import Path

from model_shelf.manifest import load_manifest
from model_shelf.resolver import (
    SUPPORTED_FORMATS,
    Config,
    check_storage_available,
)


@dataclass
class GCResult:
    """Result of a garbage-collection scan."""

    incomplete_downloads: list[str] = field(default_factory=list)
    orphaned_files: list[str] = field(default_factory=list)
    empty_dirs: list[str] = field(default_factory=list)
    total_reclaimable_bytes: int = 0

    def to_dict(self) -> dict:
        return {
            "incomplete_downloads": list(self.incomplete_downloads),
            "orphaned_files": list(self.orphaned_files),
            "empty_dirs": list(self.empty_dirs),
            "total_reclaimable_bytes": self.total_reclaimable_bytes,
        }


def _should_skip_path(path: Path) -> bool:
    """Return True if *path* should be excluded from GC scans."""
    # Dotfiles / dotdirs
    if any(part.startswith(".") for part in path.parts):
        return True
    # .cache anywhere in path
    if any(part == ".cache" or part.startswith(".cache") for part in path.parts):
        return True
    return False


def _build_tracked_set(shelf_root: Path, models: dict) -> set[str]:
    """Build a set of absolute str paths for every file listed in the manifest."""
    tracked: set[str] = set()
    for entry in models.values():
        fmt = entry.get("format", "")
        if fmt not in SUPPORTED_FORMATS:
            continue
        repo_id = entry.get("repo_id", "")
        if "/" not in repo_id:
            continue
        publisher, _, repo_name = repo_id.partition("/")
        model_dir = shelf_root / fmt / publisher / repo_name
        for fname in entry.get("files", []):
            tracked.add(str(model_dir / fname))
    return tracked


def run_gc(config: Config) -> GCResult:
    """Scan the shelf for reclaimable space.

    Detects three categories:
      - Incomplete downloads:  model dirs without the expected files
      - Orphaned files:        files on disk not tracked in the manifest
      - Empty directories:     directories that contain no files (after filtering)

    This function is read-only.  The CLI handler performs actual deletion
    when --execute is passed.
    """
    check_storage_available(config)
    shelf_root = config.shelf_root

    manifest = load_manifest(shelf_root)
    models = manifest.get("models", {})

    tracked_set = _build_tracked_set(shelf_root, models)

    incomplete: list[str] = []
    orphaned: list[str] = []
    empty_dirs: list[str] = []
    reclaimable_bytes: int = 0
    scanned_dirs: set[str] = set()

    for fmt in SUPPORTED_FORMATS:
        fmt_dir = shelf_root / fmt
        if not fmt_dir.is_dir():
            continue

        for publisher in sorted(fmt_dir.iterdir()):
            if not publisher.is_dir():
                continue
            if _should_skip_path(publisher):
                continue

            for repo in sorted(publisher.iterdir()):
                if not repo.is_dir():
                    continue
                if _should_skip_path(repo):
                    continue

                repo_str = str(repo)
                scanned_dirs.add(repo_str)

                # -- Incomplete download detection --
                if fmt == "gguf":
                    gguf_files = list(repo.glob("*.gguf"))
                    gguf_files = [f for f in gguf_files if not _should_skip_path(f)]
                    if not gguf_files:
                        incomplete.append(repo_str)
                else:
                    # MLX / safetensors
                    config_json = repo / "config.json"
                    if not config_json.is_file():
                        incomplete.append(repo_str)
                    elif fmt == "safetensors":
                        safetensor_files = [
                            f for f in repo.glob("*.safetensors")
                            if not _should_skip_path(f)
                        ]
                        if not safetensor_files:
                            incomplete.append(repo_str)

                # -- Scan for orphans inside repo dirs --
                for f in sorted(repo.rglob("*")):
                    if not f.is_file():
                        continue
                    if _should_skip_path(f):
                        continue
                    f_str = str(f)
                    if f_str not in tracked_set:
                        orphaned.append(f_str)
                        try:
                            reclaimable_bytes += f.stat().st_size
                        except OSError:
                            pass

            # Also scan for loose orphaned files at the publisher level
            for f in sorted(publisher.rglob("*")):
                if not f.is_file():
                    continue
                if _should_skip_path(f):
                    continue
                # Skip files inside repo dirs (already scanned above)
                parent_str = str(f.parent)
                if parent_str in scanned_dirs:
                    continue
                f_str = str(f)
                if f_str not in tracked_set:
                    orphaned.append(f_str)
                    try:
                        reclaimable_bytes += f.stat().st_size
                    except OSError:
                        pass

        # -- Empty directory detection (bottom-up: deepest first) --
        all_dirs = sorted(
            (d for d in fmt_dir.rglob("*") if d.is_dir()),
            key=lambda d: -len(d.parts),  # deepest first
        )
        for d in all_dirs:
            if _should_skip_path(d):
                continue
            try:
                contents = [c for c in d.iterdir()
                            if not _should_skip_path(c)]
            except OSError:
                continue
            if not contents:
                empty_dirs.append(str(d))

    return GCResult(
        incomplete_downloads=sorted(incomplete),
        orphaned_files=sorted(orphaned),
        empty_dirs=sorted(empty_dirs),
        total_reclaimable_bytes=reclaimable_bytes,
    )

edits.oldText:
    if args.command == "dedup":
        return cmd_dedup(args, cfg)
except StorageNotAvailableError as e:

edits.newText:
    if args.command == "dedup":
        return cmd_dedup(args, cfg)
    if args.command == "audit":
