                    "repo_id": "pub/repo", "format": "gguf",
                    "sha256": sha, "files": ["model.gguf"],
                    "size_bytes": model_path.stat().st_size,
                },
            },
        })

        config_path = tmp_path / "config.toml"
        write_config(config_path, shelf_root=cfg.shelf_root)

        captured = io.StringIO()
